const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
const f = body.filters || {};
return { json: { token: token, review_type: f.review_type || null, status: f.status || null, priority: f.priority || null } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const allowed = ['advisor','sub_agent','mga_principal','admin'];
if (allowed.indexOf(row.user_role) < 0) return { json: { _unauthorized: true, status: 403, error: 'Role not permitted' } };
const i = $('Extract').item.json;
return { json: { _ok: true, advisor_id: row.id || row.user_id, user_role: row.user_role, review_type: i.review_type, status: i.status, priority: i.priority } };

const raw = $input.item.json;
const rows = Array.isArray(raw) ? raw : (raw && raw.id ? [raw] : []);
const byType = {}, byStatus = {}, byPriority = {};
for (const r of rows) { byType[r.review_type] = (byType[r.review_type] || 0) + 1; byStatus[r.status] = (byStatus[r.status] || 0) + 1; byPriority[r.priority] = (byPriority[r.priority] || 0) + 1; }
return { json: { ok: true, vertical_id: 'insurance', reviews: rows, count: rows.length, breakdown: { by_type: byType, by_status: byStatus, by_priority: byPriority } } };
